import { Component } from '@angular/core';

@Component({
  selector: 'app-contact',
  standalone: true,
  template: `
    <section class="page">
      <h1>Get In Touch</h1>
      <p>Email: <a href="mailto:you@example.com">you@example.com</a></p>
    </section>
  `
})
export class ContactComponent {}
